import React, { Component } from 'react';
import { useMediaQuery } from 'react-responsive'
import Iframe from 'react-iframe'
import ucsfLogo from './images/ucsfHealth.webp'
import { Fade } from 'react-slideshow-image'
import pnImage from './images/parnassus.jpeg'
import mzImage from './images/mount-zion-2x.jpg'
import mbImage from './images/mission-bay-2x.jpg'
import 'react-slideshow-image/dist/styles.css'


const spanStyle = {
    padding: '20px',
    //background: '#efefef',
    color: '#000000'
  }

  const divStyle = {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundSize: 'cover',
    width: '100%', 
    height: '300px'
  }
  const fadeImages = [
    {
      url: pnImage,
      caption: 'UCSF Parnassus Heights Hospital'
    },
    {
      url: mbImage,
      caption: ''
    },
    {
      url: mzImage,
      caption: ''
    },
  ];



const Desktop = ({ children }) => {
    const isDesktop = useMediaQuery({ minWidth: 992 })
    return isDesktop ? children : null
  }
  const Tablet = ({ children }) => {
    const isTablet = useMediaQuery({ minWidth: 768, maxWidth: 991 })
    return isTablet ? children : null
  }
  const Mobile = ({ children }) => {
    const isMobile = useMediaQuery({ maxWidth: 767 })
    return isMobile ? children : null
  }
  const Default = ({ children }) => {
    const isNotMobile = useMediaQuery({ minWidth: 768 })
    return isNotMobile ? children : null
  }
  /*
  const spanStyle = {
    padding: '20px',
    background: '#efefef',
    color: '#000000'
  }

  const divStyle = {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundSize: 'cover',
    height: '400px'
  }
  const slideImages = [
    {
      url: 'https://images.unsplash.com/photo-1509721434272-b79147e0e708?ixlib=rb-1.2.1&ixid=eyJhcHBfaWQiOjEyMDd9&auto=format&fit=crop&w=1500&q=80',
      caption: 'Slide 1'
    },
    {
      url: 'https://images.unsplash.com/photo-1506710507565-203b9f24669b?ixlib=rb-1.2.1&ixid=eyJhcHBfaWQiOjEyMDd9&auto=format&fit=crop&w=1536&q=80',
      caption: 'Slide 2'
    },
    {
      url: 'https://images.unsplash.com/photo-1536987333706-fc9adfb10d91?ixlib=rb-1.2.1&ixid=eyJhcHBfaWQiOjEyMDd9&auto=format&fit=crop&w=1500&q=80',
      caption: 'Slide 3'
    },
  ];
  */

class responsive extends Component {

   constructor() {
      super();
      var today = new Date();
      this.state = { screen : 0, url: "", header: ""};

      //this.handleSubmit = this.handleSubmit.bind(this);
    }





    componentWillMount() {

    }

    handleSetLink = (url, name) => {

        this.setState({url: url})
        this.setState({screen: 1})
        this.setState({header: name})
      }


      handleBack = () => {
        this.setState({screen: 0})
      }






   render() {

    var showDiv = "";




    try {
        /*
      Array.from(new Set(this.state.uploadResponse.map(groups => groups.date))).map(group => {return {date: group}}).map(Record =>(
        this.inputArrayData(Record.date, items)
        //console.dir(Record)
      ))*/

/*
      showDiv = <div>
      <div style={{margin: "0px", width: "100%", backgroundColor: "#052049", color: "#fff", padding: "10px"}}><img src={ucsfWordLogo} style={{padding: "5px"}} width="40px"></img> <span style={{}}>University of California San Francisco</span></div>

      <div style={{margin: "15px"}}><img src={ucsfLogo} width="150px"></img><hr></hr></div> 
      <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex", fontSize: "30px"}}>

          Workflow Activation</div>

      <div style={{marginTop: "50px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6Zm7jjbhQ7G1K_4S0jWKbSE05LhylMV7TTs5dPZfkzba", "Parnassus")}}>Parnassus</button></div>

      <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6dyHCGdN_NChZo4S_KmRlWt8n4N47-MoJtZ3H30vG0zY", "Mission Bay")}}>Mission Bay</button></div>

      <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6SNVBWj1OemrCLetZVQCrmkev1Tzt4hEtPc3imIxyMbZ", "Mount Zion")}}>Mount Zion</button></div>

      <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6b0RZSnGOXJDPmfe8l0_XyiiEKyDhzJlvHSV_U36fObh", "VA")}}>VA</button></div>

      </div>
*/

      if (this.state.screen == 0) {
        showDiv = <div>

            <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><img src={ucsfLogo} width="150px" height="27px"></img></div> 
        <div style={{marginTop: "20px"}}>

        <div className="slide-container">
        <Fade>
         {fadeImages.map((fadeImages, index)=> (
            <div key={index}>
              <div style={{ ...divStyle, 'backgroundImage': `url(${fadeImages.url})` }}>
